load('exp2_lab2_v2.mat')

% Voltage across Diode-Connected Transistor vs Input Voltage (all three)
figure(); %[output:28e9e464]
axis equal %[output:28e9e464]
plot(V_in_120, V_q_120, '.', DisplayName='120 \Omega') %[output:28e9e464]
hold on; %[output:28e9e464]
plot(V_in_10k, V_q_10k, '.', DisplayName='10 k\Omega') %[output:28e9e464]
plot(V_in_200k, V_q_200k, '.', DisplayName='200 k\Omega') %[output:28e9e464]

fit_vals = polyfit(V_in_120(find(V_in_120 < 0.6)), V_q_120(find(V_in_120 < 0.6)), 1);
plot(linspace(0, 0.7, 101), fit_vals(1) .* linspace(0, 0.7, 101) + fit_vals(2), DisplayName=['Transistor-Dominant Regime Fit, R = 120 \Omega: y = (', num2str(fit_vals(1), 3), ' V/V)x + ', num2str(fit_vals(2), 3), ' V']) %[output:28e9e464]

fit_vals = polyfit(V_in_10k(find(V_in_10k < 0.5)), V_q_10k(find(V_in_10k < 0.5)), 1);
plot(linspace(0, 0.7, 101), fit_vals(1) .* linspace(0, 0.7, 101) + fit_vals(2), DisplayName=['Transistor-Dominant Regime Fit, R = 10 k\Omega: y = (', num2str(fit_vals(1), 3), ' V/V)x + ', num2str(fit_vals(2), 3), ' V']) %[output:28e9e464]

fit_vals = polyfit(V_in_200k(find(V_in_200k < 0.4)), V_q_200k(find(V_in_200k < 0.4)), 1);
plot(linspace(0, 0.7, 101), fit_vals(1) .* linspace(0, 0.7, 101) + fit_vals(2), DisplayName=['Transistor-Dominant Regime Fit, R = 200 k\Omega: y = (', num2str(fit_vals(1), 3), ' V/V)x + ', num2str(fit_vals(2), 3), ' V']) %[output:28e9e464]

title('Voltage Across Transistor vs. Input Voltage') %[output:28e9e464]
xlabel('V_{in} (V)') %[output:28e9e464]
ylabel('V_{Q} (V)') %[output:28e9e464]
lgd = legend(); %[output:28e9e464]
lgd.Box = 'off'; %[output:28e9e464]
lgd.Location = 'southoutside'; %[output:28e9e464]

% Current Flowing into Circuit vs. Input Voltage
figure(); %[output:33ba146a]
semilogy(V_in_120, I_in_120, '.', DisplayName='120 \Omega') %[output:33ba146a]
hold on; %[output:33ba146a]
semilogy(V_in_10k, I_in_10k, '.', DisplayName='10 k\Omega') %[output:33ba146a]
semilogy(V_in_200k, I_in_200k, '.', DisplayName='200 k\Omega') %[output:33ba146a]

plot_vals = linspace(0, 3, 1000);

vals_range = find(V_in_120 > 1);
tmp = log(I_in_120(vals_range));
coeffs = polyfit(V_in_120(vals_range), tmp,  1);
fit_vals = exp(coeffs(1).*plot_vals + coeffs(2));
semilogy(plot_vals, fit_vals, DisplayName=['Resistor-Dominant Regime Fit, R = 120 \Omega: y = e^{(', num2str(coeffs(1), 3), ' ', char(8487), ')x + ', num2str(coeffs(2), 3), ' V}']) %[output:33ba146a]

vals_range = find(V_in_10k > 2);
tmp = log(I_in_10k(vals_range));
coeffs = polyfit(V_in_10k(vals_range), tmp,  1);
fit_vals = exp(coeffs(1).*plot_vals + coeffs(2));
semilogy(plot_vals, fit_vals, DisplayName=['Resistor-Dominant Regime Fit, R = 10 k\Omega: y = e^{(', num2str(coeffs(1), 3), ' ', char(8487), ')x + ', num2str(coeffs(2), 3), ' V}']) %[output:33ba146a]

vals_range = find(V_in_200k > 2);
tmp = log(I_in_200k(vals_range));
coeffs = polyfit(V_in_200k(vals_range), tmp,  1);
fit_vals = exp(coeffs(1).*plot_vals + coeffs(2));
semilogy(plot_vals, fit_vals, DisplayName=['Resistor-Dominant Regime Fit, R = 200 k\Omega: y = e^{(', num2str(coeffs(1), 3), ' ', char(8487), ')x + ', num2str(coeffs(2), 3), ' V}']) %[output:33ba146a]

title('Current vs. Input Voltage of Circuit') %[output:33ba146a]
xlabel('V_{in} (V)') %[output:33ba146a]
ylabel('I_{in} (A)') %[output:33ba146a]
ylim([10e-9 10e-2]) %[output:33ba146a]
lgd = legend(Location="southoutside"); %[output:33ba146a]
lgd.Box = 'off'; %[output:33ba146a]

% Plot showing input current vs applied input voltage (3 plots)
U_T = 0.0191; % V; From Experiment 1 Data
I_s = 3e-15; % A

figure(); %[output:2adab962]
hold on; %[output:2adab962]
plot(V_in_120, I_in_120, '.', DisplayName='Measured Data') %[output:2adab962]
plot(log(((U_T/120)/I_s) + 1) * U_T, U_T/120, 'x', DisplayName=['(V_{on} = ', num2str(log(((U_T/120)/I_s) + 1) * U_T, 3), ' V, I_{on} = ', num2str(U_T/120, 3),' A) with U_{T} = 25 mV; I_{s} = 3 fA']) %[output:2adab962]

fit_vals = polyfit(V_in_120(find(V_in_120 < 0.6)), I_in_120(find(V_in_120 < 0.6)), 1);
plot(linspace(0, 3, 101), fit_vals(1) .* linspace(0, 3, 101) + fit_vals(2), DisplayName=['\deltaV Transistor Dominance Fit: y = (', num2str(fit_vals(1), 3), ' ', char(8487), ')x + ', num2str(fit_vals(2), 3), ' A']) %[output:2adab962]

fit_vals = polyfit(V_in_120(find(0.6 < V_in_120 & V_in_120 < 1.1)), I_in_120(find(0.6 < V_in_120 & V_in_120 < 1.1)), 1);
plot(linspace(0.5, 1.5, 101), fit_vals(1) .* linspace(0.5, 1.5, 101) + fit_vals(2), DisplayName=['\deltaV Resistor Dominance Fit: y = (', num2str(fit_vals(1), 3), ' ', char(8487), ')x + ', num2str(fit_vals(2), 3), ' A']) %[output:2adab962]

title('Circuit with 120 \Omega Resistor IV Plot') %[output:2adab962]
xlabel('V_{in} (V)') %[output:2adab962]
ylabel('I_{in} (A)') %[output:2adab962]
legend(Location='southoutside') %[output:2adab962]

figure(); %[output:82db4cd2]
hold on; %[output:82db4cd2]
plot(V_in_10k, I_in_10k, '.', DisplayName='Measured Data') %[output:82db4cd2]
